"""Test script with clearer scenario to demonstrate the getwithbase issue"""
import sys
sys.path.insert(0, '/work')

from scrapy.settings import BaseSettings

# Create a clearer scenario
# BASE: {1: 1, 2: 2}
# USER: {2: 200, 3: 30}
# If BASE is applied first, then USER should override
# Expected: {1: 1, 2: 200, 3: 30}

s = BaseSettings(
    {
        "ITEM_PIPELINES_BASE": BaseSettings({1: 1, 2: 2}, "project"),
        "ITEM_PIPELINES": BaseSettings({2: 200, 3: 30}, "default"),
    }
)

print("ITEM_PIPELINES_BASE:", dict(s["ITEM_PIPELINES_BASE"]))
print("ITEM_PIPELINES:", dict(s["ITEM_PIPELINES"]))

result = s.getwithbase("ITEM_PIPELINES")
print("getwithbase('ITEM_PIPELINES'):", dict(result))
print()

# Expected: {1: 1, 2: 200, 3: 30}
# This is because BASE should be applied first, then USER
# So key 2 should have USER's value (200) not BASE's value (2)

expected = {1: 1, 2: 200, 3: 30}
print("Expected:", expected)
print("Actual matches expected:", dict(result) == expected)
EOF
